# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
#include <cmath>
#include <chrono>
#include <random>
#include <numeric>
#include <cstring>

using namespace std;

auto START_TIME = chrono::steady_clock::now();
mt19937 rng(42);

double elapsed() {
    return chrono::duration<double>(chrono::steady_clock::now() - START_TIME).count();
}

int N, M;

struct FastSolver {
    vector<vector<int>> initial_stacks;
    vector<int> plan; // plan[k] = dest stack for boxes above target k

    void init(const vector<vector<int>>& is) {
        initial_stacks = is;
        plan.resize(N);
    }

    long long simulate() {
        // Use flat arrays for speed
        static int st_data[10][400];
        static int st_size[10];
        static int bp_stack[200];
        static int bp_height[200];

        for (int i = 0; i < M; i++) {
            st_size[i] = initial_stacks[i].size();
            for (int j = 0; j < st_size[i]; j++) {
                st_data[i][j] = initial_stacks[i][j];
                bp_stack[initial_stacks[i][j]] = i;
                bp_height[initial_stacks[i][j]] = j;
            }
        }

        long long en = 0;
        for (int k = 0; k < N; k++) {
            int src = bp_stack[k];
            int h = bp_height[k];
            int pile_size = st_size[src] - 1 - h;

            if (pile_size > 0) {
                int dest = plan[k];
                if (dest == src) dest = (src + 1) % M;

                int old_dest_h = st_size[dest];
                for (int i = h + 1; i < st_size[src]; i++) {
                    int box = st_data[src][i];
                    st_data[dest][old_dest_h + (i - h - 1)] = box;
                    bp_stack[box] = dest;
                    bp_height[box] = old_dest_h + (i - h - 1);
                }
                st_size[dest] += pile_size;
                st_size[src] = h + 1;
                en += pile_size + 1;
            }
            st_size[src]--;
        }
        return en;
    }

    void output_solution() {
        static int st_data[10][400];
        static int st_size[10];
        static int bp_stack[200];
        static int bp_height[200];

        for (int i = 0; i < M; i++) {
            st_size[i] = initial_stacks[i].size();
            for (int j = 0; j < st_size[i]; j++) {
                st_data[i][j] = initial_stacks[i][j];
                bp_stack[initial_stacks[i][j]] = i;
                bp_height[initial_stacks[i][j]] = j;
            }
        }

        for (int k = 0; k < N; k++) {
            int src = bp_stack[k];
            int h = bp_height[k];
            int pile_size = st_size[src] - 1 - h;

            if (pile_size > 0) {
                int dest = plan[k];
                if (dest == src) dest = (src + 1) % M;

                int first_box = st_data[src][h + 1];
                cout << (first_box + 1) << " " << (dest + 1) << "\n";

                int old_dest_h = st_size[dest];
                for (int i = h + 1; i < st_size[src]; i++) {
                    int box = st_data[src][i];
                    st_data[dest][old_dest_h + (i - h - 1)] = box;
                    bp_stack[box] = dest;
                    bp_height[box] = old_dest_h + (i - h - 1);
                }
                st_size[dest] += pile_size;
                st_size[src] = h + 1;
            }
            st_size[src]--;
            cout << (k + 1) << " 0\n";
        }
    }

    void generate_greedy_plan() {
        static int st_data[10][400];
        static int st_size[10];
        static int bp_stack[200];
        static int bp_height[200];

        for (int i = 0; i < M; i++) {
            st_size[i] = initial_stacks[i].size();
            for (int j = 0; j < st_size[i]; j++) {
                st_data[i][j] = initial_stacks[i][j];
                bp_stack[initial_stacks[i][j]] = i;
                bp_height[initial_stacks[i][j]] = j;
            }
        }

        for (int k = 0; k < N; k++) {
            int src = bp_stack[k];
            int h = bp_height[k];
            int pile_size = st_size[src] - 1 - h;

            if (pile_size == 0) {
                plan[k] = src;
                st_size[src]--;
                continue;
            }

            double best_score = 1e18;
            int best_d = (src + 1) % M;
            for (int d = 0; d < M; d++) {
                if (d == src) continue;
                double score = 0;
                for (int idx = 0; idx < st_size[d]; idx++) {
                    int b = st_data[d][idx];
                    if (b > k) {
                        double dist = b - k;
                        score += pile_size * (1.0 / dist) * 3.0;
                    }
                }
                for (int i = h + 1; i < st_size[src]; i++) {
                    int b = st_data[src][i];
                    int above = st_size[src] - 1 - i;
                    if (b > k && above > 0) {
                        double dist = b - k;
                        score += above * (1.0 / dist) * 5.0;
                    }
                }
                score += st_size[d] * 0.1;
                if (st_size[d] == 0) score -= 2.0;
                if (score < best_score) {
                    best_score = score;
                    best_d = d;
                }
            }
            plan[k] = best_d;

            int old_dest_h = st_size[best_d];
            for (int i = h + 1; i < st_size[src]; i++) {
                int box = st_data[src][i];
                st_data[best_d][old_dest_h + (i - h - 1)] = box;
                bp_stack[box] = best_d;
                bp_height[box] = old_dest_h + (i - h - 1);
            }
            st_size[best_d] += pile_size;
            st_size[src] = h + 1;
            st_size[src]--;
        }
    }

    void sa_optimize(double time_limit) {
        long long cur_energy = simulate();
        long long best_en = cur_energy;
        vector<int> best_plan = plan;

        double t0 = 50.0, t1 = 0.05;
        double start = elapsed();
        double total_time = time_limit - start;
        if (total_time <= 0.01) return;

        int iter = 0;
        int max_block = max(1, N / 8);
        uniform_int_distribution<int> idx_dist(0, N - 1);
        uniform_int_distribution<int> val_dist(0, M - 1);
        uniform_real_distribution<double> prob_dist(0.0, 1.0);

        while (true) {
            if ((iter & 1023) == 0) {
                if (elapsed() >= time_limit) break;
            }
            iter++;

            double progress = (elapsed() - start) / total_time;
            if (progress >= 1.0) break;
            double temp = t0 * pow(t1 / t0, progress);

            int op_type = rng() % 100;

            if (op_type < 55) {
                // Single point mutation
                int idx = idx_dist(rng);
                int old_val = plan[idx];
                int new_val = val_dist(rng);
                if (new_val == old_val) continue;

                plan[idx] = new_val;
                long long new_energy = simulate();

                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        best_plan = plan;
                    }
                } else {
                    plan[idx] = old_val;
                }
            } else if (op_type < 85) {
                // Block mutation
                int len = 2 + rng() % max_block;
                int idx = idx_dist(rng);

                static int old_vals[30];
                int actual_len = min(len, N - idx);
                for (int i = 0; i < actual_len; i++) {
                    old_vals[i] = plan[idx + i];
                    plan[idx + i] = val_dist(rng);
                }

                long long new_energy = simulate();
                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        best_plan = plan;
                    }
                } else {
                    for (int i = 0; i < actual_len; i++) plan[idx + i] = old_vals[i];
                }
            } else {
                // Swap two plan entries
                int i1 = idx_dist(rng);
                int i2 = idx_dist(rng);
                if (i1 == i2) continue;

                swap(plan[i1], plan[i2]);
                long long new_energy = simulate();
                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        best_plan = plan;
                    }
                } else {
                    swap(plan[i1], plan[i2]);
                }
            }
        }
        plan = best_plan;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    START_TIME = chrono::steady_clock::now();

    cin >> N >> M;
    vector<vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        int h = N / M;
        initial_stacks[i].resize(h);
        for (int j = 0; j < h; j++) {
            cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    FastSolver solver;
    solver.init(initial_stacks);
    solver.generate_greedy_plan();
    solver.sa_optimize(1.90);
    solver.output_solution();

    return 0;
}
