# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
#include <cmath>
#include <chrono>
#include <random>
#include <numeric>
#include <cstring>

using namespace std;

auto START_TIME = chrono::steady_clock::now();
mt19937 rng(42);

double elapsed() {
    return chrono::duration<double>(chrono::steady_clock::now() - START_TIME).count();
}

int N, M;

struct State {
    int st_data[10][400];
    int st_size[10];
    int bp_stack[200];
    int bp_height[200];
};

struct Solver {
    vector<vector<int>> initial_stacks;
    int plan[200]; // plan[k] = dest stack for boxes above target k

    void init(const vector<vector<int>>& is) {
        initial_stacks = is;
    }

    void get_initial_state(State& s) {
        for (int i = 0; i < M; i++) {
            s.st_size[i] = initial_stacks[i].size();
            for (int j = 0; j < s.st_size[i]; j++) {
                s.st_data[i][j] = initial_stacks[i][j];
                s.bp_stack[initial_stacks[i][j]] = i;
                s.bp_height[initial_stacks[i][j]] = j;
            }
        }
    }

    // Execute one step: move pile above target k to plan[k], then remove k
    // Returns energy cost of this step
    inline int execute_step(State& s, int k) {
        int src = s.bp_stack[k];
        int h = s.bp_height[k];
        int pile_size = s.st_size[src] - 1 - h;
        int en = 0;

        if (pile_size > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;

            int old_dest_h = s.st_size[dest];
            for (int i = h + 1; i < s.st_size[src]; i++) {
                int box = s.st_data[src][i];
                s.st_data[dest][old_dest_h + (i - h - 1)] = box;
                s.bp_stack[box] = dest;
                s.bp_height[box] = old_dest_h + (i - h - 1);
            }
            s.st_size[dest] += pile_size;
            s.st_size[src] = h + 1;
            en = pile_size + 1;
        }
        // Remove target k
        s.st_size[src]--;
        return en;
    }

    long long simulate() {
        State s;
        get_initial_state(s);
        long long en = 0;
        for (int k = 0; k < N; k++) {
            en += execute_step(s, k);
        }
        return en;
    }

    // Simulate from step 'from' given state s, return total energy from 'from' to end
    long long simulate_from(State& s, int from) {
        long long en = 0;
        for (int k = from; k < N; k++) {
