    // Greedy choice for step k given current state: pick best destination
    int greedy_choice(const State& s, int k) {
        int src = s.bp_stack[k];
        int h = s.bp_height[k];
        int pile_size = s.st_size[src] - 1 - h;

        if (pile_size == 0) return src;

        double best_score = 1e18;
        int best_d = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0;

            // Penalty: covering future targets in destination
            // For each future target in dest, count pile boxes that will be above it with number > target
            for (int idx = 0; idx < s.st_size[d]; idx++) {
                int b = s.st_data[d][idx];
                if (b > k) {
                    // b is a future target; pile will land on top of it
                    // Count how many pile boxes have number > b (will still be there when b is needed)
                    int covering = 0;
                    for (int i = h + 1; i < s.st_size[src]; i++) {
                        if (s.st_data[src][i] > b) covering++;
                    }
                    double dist = b - k;
                    score += covering * (1.0 / dist) * 4.0;
                    // Also penalty for pile boxes with number < b that cover b temporarily
                    score += (pile_size - covering) * (1.0 / dist) * 1.0;
                }
            }

            // Penalty for pile targets being covered by other pile boxes
            for (int i = h + 1; i < s.st_size[src]; i++) {
                int b = s.st_data[src][i];
                if (b > k) {
