                        score += above_in_pile * (1.0 / dist) * 3.0;
                    }
                }
            }

            // Small stack height penalty
            score += s.st_size[d] * 0.05;
            // Reward empty stacks
            if (s.st_size[d] == 0) score -= 3.0;

            if (score < best_score) {
                best_score = score;
                best_d = d;
            }
        }
        return best_d;
    }

