        State checkpoints[11]; // max 200/20 = 10 checkpoints + 1
        int checkpoint_steps[11];
        long long energy_prefix[201]; // energy_prefix[k] = total energy for steps 0..k-1

        auto rebuild_checkpoints = [&]() {
            State s;
            get_initial_state(s);
            checkpoints[0] = s;
            checkpoint_steps[0] = 0;
            energy_prefix[0] = 0;
            int cp_idx = 1;
            for (int k = 0; k < N; k++) {
                energy_prefix[k + 1] = energy_prefix[k] + execute_step(s, k);
                if ((k + 1) % CHECKPOINT_INTERVAL == 0 && cp_idx < NUM_CHECKPOINTS) {
                    checkpoints[cp_idx] = s;
                    checkpoint_steps[cp_idx] = k + 1;
                    cp_idx++;
                }
            }
        };

        rebuild_checkpoints();

        double t0 = 50.0, t1 = 0.05;
        double start = elapsed();
        double total_time = time_limit - start;
        if (total_time <= 0.01) return;

        int iter = 0;
        int rebuild_counter = 0;
        const int REBUILD_INTERVAL = 500;

        uniform_int_distribution<int> idx_dist(0, N - 1);
        uniform_int_distribution<int> val_dist(0, M - 1);
        uniform_real_distribution<double> prob_dist(0.0, 1.0);

        while (true) {
            if ((iter & 511) == 0) {
                if (elapsed() >= time_limit) break;
            }
            iter++;

            double progress = (elapsed() - start) / total_time;
            if (progress >= 1.0) break;
            double temp = t0 * pow(t1 / t0, progress);

            int op_type = rng() % 100;

            if (op_type < 40) {
                // Ruin-and-recreate: mutate one position, greedy-repair a cascade
                int pos = idx_dist(rng);
                int new_val = val_dist(rng);
                int old_plan_segment[50];
                int cascade_len = 3 + rng() % 12; // 3 to 14 steps of cascade
                int segment_end = min(N, pos + 1 + cascade_len);
                int segment_len = segment_end - pos;
                memcpy(old_plan_segment, &plan[pos], segment_len * sizeof(int));

                // Find appropriate checkpoint
                int cp_idx = pos / CHECKPOINT_INTERVAL;
                if (cp_idx >= NUM_CHECKPOINTS) cp_idx = NUM_CHECKPOINTS - 1;

                // Apply ruin-and-recreate
                State s;
                memcpy(&s, &checkpoints[cp_idx], sizeof(State));
                for (int k = checkpoint_steps[cp_idx]; k < pos; k++) {
                    execute_step(s, k);
                }

                plan[pos] = new_val;
                execute_step(s, pos);

                for (int k = pos + 1; k < segment_end; k++) {
                    plan[k] = greedy_choice(s, k);
                    execute_step(s, k);
                }

                // Continue simulation to get remaining energy
                long long new_energy = energy_prefix[checkpoint_steps[cp_idx]];
                {
                    State s2;
                    memcpy(&s2, &checkpoints[cp_idx], sizeof(State));
                    for (int k = checkpoint_steps[cp_idx]; k < N; k++) {
                        new_energy += execute_step(s2, k) - (k >= checkpoint_steps[cp_idx] ? 0 : 0);
                    }
                    // Recompute properly
                    new_energy = 0;
                    get_initial_state(s2);
                    for (int k = 0; k < N; k++) {
                        new_energy += execute_step(s2, k);
                    }
                }

                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    rebuild_counter++;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        memcpy(best_plan, plan, sizeof(plan));
                    }
                    if (rebuild_counter >= REBUILD_INTERVAL) {
                        rebuild_checkpoints();
                        rebuild_counter = 0;
                    }
                } else {
                    memcpy(&plan[pos], old_plan_segment, segment_len * sizeof(int));
                }
            } else if (op_type < 70) {
                // Single point mutation (standard)
                int idx = idx_dist(rng);
                int old_val = plan[idx];
                int new_val = val_dist(rng);
                if (new_val == old_val) continue;

                plan[idx] = new_val;
                long long new_energy = simulate();

