mt19937 rng(42);

double elapsed() {
    return chrono::duration<double>(chrono::steady_clock::now() - START_TIME).count();
}

int N, M;

struct State {
    int st_data[10][400];
    int st_size[10];
    int bp_stack[200];
    int bp_height[200];
};

struct Solver {
    vector<vector<int>> initial_stacks;
    int plan[200];

    // Checkpoint system for incremental evaluation
    static const int CP_INTERVAL = 10;
    State checkpoints[21]; // max 200/10 = 20 + initial
    long long energy_at[201]; // cumulative energy at step k (energy_at[k] = sum of energy for steps 0..k-1)
    int num_checkpoints;

    void init(const vector<vector<int>>& is) {
        initial_stacks = is;
        num_checkpoints = N / CP_INTERVAL + 1;
    }

    void get_initial_state(State& s) {
        for (int i = 0; i < M; i++) {
            s.st_size[i] = initial_stacks[i].size();
            for (int j = 0; j < s.st_size[i]; j++) {
                s.st_data[i][j] = initial_stacks[i][j];
                s.bp_stack[initial_stacks[i][j]] = i;
                s.bp_height[initial_stacks[i][j]] = j;
            }
        }
    }

    inline int execute_step(State& s, int k) {
        int src = s.bp_stack[k];
        int h = s.bp_height[k];
        int pile_size = s.st_size[src] - 1 - h;
        int en = 0;

        if (pile_size > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;

            int old_dest_h = s.st_size[dest];
            for (int i = h + 1; i < s.st_size[src]; i++) {
                int box = s.st_data[src][i];
                s.st_data[dest][old_dest_h + (i - h - 1)] = box;
                s.bp_stack[box] = dest;
                s.bp_height[box] = old_dest_h + (i - h - 1);
            }
            s.st_size[dest] += pile_size;
            s.st_size[src] = h + 1;
            en = pile_size + 1;
        }
        s.st_size[src]--;
        return en;
    }

    long long simulate() {
        State s;
        get_initial_state(s);
        long long en = 0;
        for (int k = 0; k < N; k++) {
            en += execute_step(s, k);
        }
        return en;
    }

    // Build checkpoints and energy prefix array
    void build_checkpoints() {
        State s;
        get_initial_state(s);
        checkpoints[0] = s;
        energy_at[0] = 0;

        for (int k = 0; k < N; k++) {
            int en = execute_step(s, k);
            energy_at[k + 1] = energy_at[k] + en;
            if ((k + 1) % CP_INTERVAL == 0) {
                int cp_idx = (k + 1) / CP_INTERVAL;
                checkpoints[cp_idx] = s;
            }
        }
    }

    // Evaluate energy from step 'from' to end, given current plan, starting from checkpoint
    long long eval_from(int from) {
        int cp_idx = from / CP_INTERVAL;
        int cp_start = cp_idx * CP_INTERVAL;

        State s;
        memcpy(&s, &checkpoints[cp_idx], sizeof(State));

        long long en = 0;
        for (int k = cp_start; k < N; k++) {
            en += execute_step(s, k);
        }
        return energy_at[cp_start] + en;
    }

    void generate_greedy_plan() {
        State s;
        get_initial_state(s);

        for (int k = 0; k < N; k++) {
            int src = s.bp_stack[k];
            int h = s.bp_height[k];
            int pile_size = s.st_size[src] - 1 - h;

            if (pile_size == 0) {
                plan[k] = src;
                execute_step(s, k);
                continue;
            }

            double best_score = 1e18;
            int best_d = (src + 1) % M;
            for (int d = 0; d < M; d++) {
                if (d == src) continue;
                double score = 0;
                for (int idx = 0; idx < s.st_size[d]; idx++) {
                    int b = s.st_data[d][idx];
                    if (b > k) {
                        double dist = b - k;
                        score += pile_size * (1.0 / dist) * 3.0;
                    }
                }
                for (int i = h + 1; i < s.st_size[src]; i++) {
                    int b = s.st_data[src][i];
                    int above = s.st_size[src] - 1 - i;
                    if (b > k && above > 0) {
                        double dist = b - k;
                        score += above * (1.0 / dist) * 5.0;
                    }
                }
                score += s.st_size[d] * 0.1;
                if (s.st_size[d] == 0) score -= 2.0;
                if (score < best_score) {
                    best_score = score;
                    best_d = d;
                }
            }
            plan[k] = best_d;
            execute_step(s, k);
        }
    }

    void sa_optimize(double time_limit) {
        build_checkpoints();
        long long cur_energy = energy_at[N];
        long long best_en = cur_energy;
        int best_plan[200];
        memcpy(best_plan, plan, sizeof(plan));

        double t0 = 50.0, t1 = 0.05;
        double start = elapsed();
        double total_time = time_limit - start;
        if (total_time <= 0.01) return;

        int iter = 0;
        int accepted_since_rebuild = 0;
        int max_block = max(1, N / 8);
        uniform_int_distribution<int> idx_dist(0, N - 1);
        uniform_int_distribution<int> val_dist(0, M - 1);
        uniform_real_distribution<double> prob_dist(0.0, 1.0);

        while (true) {
            if ((iter & 1023) == 0) {
                if (elapsed() >= time_limit) break;
            }
            iter++;

            double progress = (elapsed() - start) / total_time;
            if (progress >= 1.0) break;
            double temp = t0 * pow(t1 / t0, progress);

            int op_type = rng() % 100;

            if (op_type < 55) {
                // Single point mutation with incremental eval
                int idx = idx_dist(rng);
                int old_val = plan[idx];
                int new_val = val_dist(rng);
                if (new_val == old_val) continue;

                plan[idx] = new_val;
                long long new_energy = eval_from(idx);

                long long delta = new_energy - cur_energy;
