                    accepted_since_rebuild++;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        memcpy(best_plan, plan, sizeof(plan));
                    }
                    // Rebuild checkpoints periodically
                    if (accepted_since_rebuild >= 200) {
                        build_checkpoints();
                        cur_energy = energy_at[N];
                        accepted_since_rebuild = 0;
                    }
                } else {
                    plan[idx] = old_val;
                }
            } else if (op_type < 85) {
                // Block mutation with incremental eval
                int len = 2 + rng() % max_block;
                int idx = idx_dist(rng);

                int old_vals[30];
                int actual_len = min(len, N - idx);
                for (int i = 0; i < actual_len; i++) {
                    old_vals[i] = plan[idx + i];
                    plan[idx + i] = val_dist(rng);
                }

                long long new_energy = eval_from(idx);
                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    accepted_since_rebuild++;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        memcpy(best_plan, plan, sizeof(plan));
                    }
                    if (accepted_since_rebuild >= 200) {
                        build_checkpoints();
                        cur_energy = energy_at[N];
                        accepted_since_rebuild = 0;
                    }
                } else {
                    for (int i = 0; i < actual_len; i++) plan[idx + i] = old_vals[i];
                }
            } else {
                // Swap two plan entries with incremental eval
                int i1 = idx_dist(rng);
                int i2 = idx_dist(rng);
                if (i1 == i2) continue;

                swap(plan[i1], plan[i2]);
                int eval_pos = min(i1, i2);
                long long new_energy = eval_from(eval_pos);
                long long delta = new_energy - cur_energy;
                if (delta <= 0 || prob_dist(rng) < exp(-(double)delta / temp)) {
                    cur_energy = new_energy;
                    accepted_since_rebuild++;
                    if (cur_energy < best_en) {
                        best_en = cur_energy;
                        memcpy(best_plan, plan, sizeof(plan));
                    }
                    if (accepted_since_rebuild >= 200) {
                        build_checkpoints();
                        cur_energy = energy_at[N];
                        accepted_since_rebuild = 0;
                    }
                } else {
                    swap(plan[i1], plan[i2]);
                }
            }
        }
        memcpy(plan, best_plan, sizeof(plan));
    }

    void output_solution() {
        State s;
        get_initial_state(s);

        for (int k = 0; k < N; k++) {
            int src = s.bp_stack[k];
            int h = s.bp_height[k];
            int pile_size = s.st_size[src] - 1 - h;

            if (pile_size > 0) {
                int dest = plan[k];
                if (dest == src) dest = (src + 1) % M;

                int first_box = s.st_data[src][h + 1];
                cout << (first_box + 1) << " " << (dest + 1) << "\n";

                int old_dest_h = s.st_size[dest];
                for (int i = h + 1; i < s.st_size[src]; i++) {
                    int box = s.st_data[src][i];
                    s.st_data[dest][old_dest_h + (i - h - 1)] = box;
                    s.bp_stack[box] = dest;
                    s.bp_height[box] = old_dest_h + (i - h - 1);
                }
                s.st_size[dest] += pile_size;
                s.st_size[src] = h + 1;
            }
            s.st_size[src]--;
            cout << (k + 1) << " 0\n";
        }
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    START_TIME = chrono::steady_clock::now();

    cin >> N >> M;
    vector<vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        int h = N / M;
        initial_stacks[i].resize(h);
        for (int j = 0; j < h; j++) {
            cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    Solver solver;
    solver.init(initial_stacks);
    solver.generate_greedy_plan();
    solver.sa_optimize(1.90);
    solver.output_solution();

    return 0;
}
